import wave, struct, math, statistics
p='/app/media/audio_engine_002.wav'
with wave.open(p,'rb') as w:
    sr=w.getframerate(); data=w.readframes(w.getnframes())
s=list(struct.unpack('<%dh'%(len(data)//2),data)); mean=sum(s)/len(s); x=[v-mean for v in s]
W,H=1200,500
img=[[(255,255,255) for _ in range(W)] for __ in range(H)]
def setpix(xp,yp,c):
    if 0<=xp<W and 0<=yp<H: img[yp][xp]=c
# grid vertical seconds, horizontal axes
for sec in range(6):
    xp=int(sec/5*W)
    for y in range(H): setpix(xp,y,(230,230,230))
for y in [125,250,375]:
    for xp in range(W): setpix(xp,y,(235,235,235))
# waveform minmax per pixel top half
maxabs=max(abs(v) for v in x)
for xp in range(W):
    a=int(xp*len(x)/W); b=int((xp+1)*len(x)/W); seg=x[a:b] or [0]
    mn=min(seg)/maxabs; mx=max(seg)/maxabs
    y1=int(125 - mx*110); y2=int(125 - mn*110)
    for y in range(min(y1,y2),max(y1,y2)+1): setpix(xp,y,(30,80,180))
# RMS 5ms envelope bottom half scaled
win=int(sr*.005); vals=[]
for i in range(0,len(x)-win+1,win): vals.append(math.sqrt(sum(v*v for v in x[i:i+win])/win))
mx=max(vals)
prev=None
for i,v in enumerate(vals):
    xp=int((i/(len(vals)-1))* (W-1)); yp=int(470 - (v/mx)*190)
    if prev:
        x0,y0=prev; dx=xp-x0 or 1
        for xx in range(min(x0,xp),max(x0,xp)+1):
            t=(xx-x0)/(xp-x0) if xp"'!=x0 else 0
            yy=int(y0+(yp-y0)*t)
            for off in [-1,0,1]: setpix(xx,yy+off,(200,40,40))
    prev=(xp,yp)
# Add weak event markers from grid phase 5 at bottom
period=0.0375; phase=0.01
for j in range(133):
    t=phase+j*period; idx=int(t/0.005)
    if 0<=idx<len(vals) and vals[idx]<3000:
        xp=int(t/5*W)
        for y in range(280,480):
            if y%3!=0: setpix(xp,y,(0,0,0))
# write PPM
out='"'/app/audio_engine_002_plot.ppm'
with open(out,'wb') as f:
    f.write(f'P6\\n{W} {H}\\n255\\n'.encode())
    for row in img:
        for r,g,b in row:
            f.write(bytes([r,g,b]))
print(out)
